mapper.jsonStringBodyContent:
{
  "model": "llama-3.3-70b-versatile",
  "temperature": 0.2,
  "messages": [
    {
      "role": "system",
      "content": "You are a Scrum assistant analyzing Slack standup messages. Classify into exactly one of: NEW_BLOCKER, RESOLVED_BLOCKER, IRRELEVANT. If NEW_BLOCKER or RESOLVED_BLOCKER, extract a short description (max 15 words). Respond ONLY with valid JSON, no preamble, no markdown: {\"category\": \"...\", \"description\": \"...\"}"
    },
    {
      "role": "user",
      "content": "{{27.sanitizedSlackmessage}}"
    }
  ]
}

{
  "model": "llama-3.3-70b-versatile",
  "temperature": 0.4,
  "messages": [
    {
      "role": "system",
      "content": "You are a Scrum assistant. Generate a concise Slack escalation alert in Slack markdown format (use *bold* with single asterisks, not double). Include: an urgency emoji (🟡 for Low, 🟠 for Medium, 🔴 for High), the urgency level, the blocker description, days blocked, and a brief suggested next action (1 sentence). Keep total under 60 words. Respond with ONLY the formatted message text, no JSON, no preamble."
    },
    {
      "role": "user",
      "content": "Urgency: {{22.urgency}}. Blocker:{{3.description}} . Days blocked: 1."
    }
  ]
}

{
  "model": "llama-3.3-70b-versatile",
  "temperature": 0.1,
  "messages": [
    {
      "role": "system",
      "content": "You are a blocker resolution matcher. Match the resolution message to the correct open blocker from the list and return its row number. Respond ONLY in valid JSON with no markdown, no extra text."
    },
    {
      "role": "user",
      "content": "Resolution message:\n\"{{3.description}}\"\n\nOpen blockers:\n\"{{36.sanitized_open_blockers}}\"\n\nRespond ONLY with:\n{\"matched_row\": <row number or null>, \"reason\": \"one sentence\"}"
    }
  ]
}

